import{_ as i,o as t,c as n,ag as a}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"Über Dotfiles (DE)","titleTemplate":":title","description":"Die nächste Generation der Shell-Konfiguration. Hochleistungsfähig, sicher und AI-nativ. Verwaltet von Chezmoi.","frontmatter":{"title":"Über Dotfiles","description":"Die nächste Generation der Shell-Konfiguration. Hochleistungsfähig, sicher und AI-nativ. Verwaltet von Chezmoi.","lang":"de-DE","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Über Dotfiles preview","canonical":"/de/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Über Dotfiles","pageType":"docs","schemaType":"WebPage","metaTitle":"Über Dotfiles - Dotfiles (DE)","permalink":"/de/about/","sidebar":true,"meta":[{"name":"keywords","content":"chezmoi, dotfiles, konfiguration, automatisierung, macos, linux, rust, zellij, shell, terminal"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Die nächste Generation der Shell-Konfiguration. Hochleistungsfähig, sicher und AI-nativ. Verwaltet von Chezmoi."},{"name":"twitter:title","content":"Über Dotfiles"},{"name":"og:title","content":"Über Dotfiles"},{"name":"og:description","content":"Die nächste Generation der Shell-Konfiguration. Hochleistungsfähig, sicher und AI-nativ. Verwaltet von Chezmoi."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"de_DE"}]},"headers":[],"relativePath":"de/about/index.md","filePath":"de/about/index.md","lastUpdated":1773010926000}'),l={name:"de/about/index.md"};function s(o,e,r,d,c,h){return t(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="uber-dotfiles" tabindex="-1">Über Dotfiles <a class="header-anchor" href="#uber-dotfiles" aria-label="Permalink to &quot;Über Dotfiles&quot;">​</a></h1><p>Der moderne Standard für Shell-Konfiguration. Basiert auf <strong>Chezmoi</strong> für sichere, plattformübergreifende Umgebungsverwaltung.</p><h2 id="entdecken" tabindex="-1">Entdecken <a class="header-anchor" href="#entdecken" aria-label="Permalink to &quot;Entdecken&quot;">​</a></h2><p>Dotfiles v0.2.495 transformiert Ihr Terminal in einen leistungsstarken, einheitlichen Arbeitsbereich. Im Gegensatz zu alten Dotfiles, die auf komplexen Makefiles oder Symlink-Skripten basieren, verwendet Dotfiles einen vorlagenbasierten Ansatz, der atomar, schnell und reproduzierbar ist.</p><h3 id="was-ist-neu" tabindex="-1">Was ist neu <a class="header-anchor" href="#was-ist-neu" aria-label="Permalink to &quot;Was ist neu&quot;">​</a></h3><ul><li><strong>Moderner Kern</strong> — Hochleistungs-Rust-Alternativen ersetzen alte Unix-Tools: <ul><li><strong>Atuin</strong> für Shell-Verlauf</li><li><strong>Yazi</strong> für Dateiverwaltung</li><li><strong>Zellij</strong> für Terminal-Multiplexing</li><li><strong>Ghostty</strong> für GPU-beschleunigtes Terminal</li><li><strong>NeoVim</strong> für modernes Editieren</li></ul></li><li><strong>Native Sicherheit</strong> — Vollständig native SSH-Signierung ohne Drittanbieter-Agenten</li><li><strong>Interaktiver Modus</strong> — Neuer <code>dot learn</code> Befehl führt Sie durch die Funktionen</li></ul><h2 id="erste-schritte" tabindex="-1">Erste Schritte <a class="header-anchor" href="#erste-schritte" aria-label="Permalink to &quot;Erste Schritte&quot;">​</a></h2><h3 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h3><ul><li><strong>macOS</strong>, <strong>Linux (Ubuntu/Debian)</strong> oder <strong>Windows (WSL)</strong></li><li><strong>Curl</strong> und <strong>Git</strong></li><li><strong>Chezmoi</strong> (wird automatisch installiert)</li><li><strong>Nerd Font</strong> (für Terminal-Icons)</li></ul><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><p>Führen Sie einen einzigen Befehl aus, um die gesamte Suite zu installieren:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><p>Der Installer wird:</p><ol><li>Die <code>chezmoi</code>-Binärdatei installieren</li><li>Das Repository klonen</li><li>Erforderliche Pakete über Homebrew (macOS) oder Apt (Linux) installieren</li><li>Ihre Konfiguration anwenden</li></ol><h3 id="erkunden" tabindex="-1">Erkunden <a class="header-anchor" href="#erkunden" aria-label="Permalink to &quot;Erkunden&quot;">​</a></h3><p>Nach der Installation starten Sie Ihr Terminal neu und führen Sie aus:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> learn</span></span></code></pre></div><p>Dies startet eine interaktive Tour durch Ihre neue Umgebung.</p><h2 id="anpassen" tabindex="-1">Anpassen <a class="header-anchor" href="#anpassen" aria-label="Permalink to &quot;Anpassen&quot;">​</a></h2><p>Ihre Konfiguration befindet sich in <code>~/.local/share/chezmoi</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.local/share/chezmoi</span></span>
<span class="line"><span>├── dot_zshenv              # Shell-Einstiegspunkt</span></span>
<span class="line"><span>├── dot_config/             # XDG-Basiskonfiguration (~/.config)</span></span>
<span class="line"><span>│   ├── atuin/              # Shell-Verlauf</span></span>
<span class="line"><span>│   ├── ghostty/            # Terminal-Emulator</span></span>
<span class="line"><span>│   ├── git/                # Git-Konfiguration</span></span>
<span class="line"><span>│   ├── yazi/               # Dateimanager</span></span>
<span class="line"><span>│   ├── zellij/             # Terminal-Multiplexer</span></span>
<span class="line"><span>│   ├── zsh/                # Zsh-Konfiguration</span></span>
<span class="line"><span>│   └── shell/              # Gemeinsame Aliase und Pfade</span></span>
<span class="line"><span>├── provision/              # Lifecycle-Skripte</span></span>
<span class="line"><span>├── install.sh              # Universeller Installer</span></span>
<span class="line"><span>└── docs/                   # Dokumentation</span></span></code></pre></div><h2 id="kernbefehle" tabindex="-1">Kernbefehle <a class="header-anchor" href="#kernbefehle" aria-label="Permalink to &quot;Kernbefehle&quot;">​</a></h2><p>Die <code>dot</code>-CLI bietet 53 Befehle, organisiert nach Kategorie.</p><h3 id="kern" tabindex="-1">Kern <a class="header-anchor" href="#kern" aria-label="Permalink to &quot;Kern&quot;">​</a></h3><ul><li><code>dot apply</code> — wendet Konfigurationsänderungen an.</li><li><code>dot sync</code> — holt den neuesten Repository-Stand und wendet ihn an.</li><li><code>dot update</code> — aktualisiert das Repository und wärmt Caches vor.</li><li><code>dot add</code> — fügt neue Dateien in die Chezmoi-Quelle ein.</li><li><code>dot diff</code> — zeigt ausstehende Änderungen vor dem Anwenden.</li><li><code>dot status</code> — zeigt den Status verwalteter Dateien an.</li><li><code>dot remove</code> — entfernt eine Datei aus der Verwaltung und löscht den Quelleintrag.</li><li><code>dot cd</code> — öffnet eine Shell im Chezmoi-Quellverzeichnis.</li><li><code>dot edit</code> — öffnet eine verwaltete Datei in Ihrem Editor.</li><li><code>dot clean-cache</code> — löscht temporäre Caches.</li><li><code>dot prewarm</code> — füllt Caches für schnelleren Shell-Start vor.</li></ul><h3 id="diagnose" tabindex="-1">Diagnose <a class="header-anchor" href="#diagnose" aria-label="Permalink to &quot;Diagnose&quot;">​</a></h3><ul><li><code>dot doctor</code> — prüft Pfade, Tools und Shell-Zustand.</li><li><code>dot heal</code> — repariert fehlenden oder fehlerhaften Zustand automatisch.</li><li><code>dot health</code> — führt eine leichtgewichtige Gesundheitsprüfung durch.</li><li><code>dot verify</code> — prüft Dateiintegrität gegen die Quelle.</li><li><code>dot scorecard</code> — gibt eine Konfigurationsqualitätsbewertung aus.</li><li><code>dot snapshot</code> — erfasst den aktuellen Zustand für späteren Vergleich.</li><li><code>dot smoke-test</code> — validiert Kern-Toolchains vollständig.</li><li><code>dot chaos</code> — injiziert Fehler zum Testen der Selbstheilung.</li><li><code>dot bundle</code> — exportiert ein portables Konfigurationspaket.</li><li><code>dot rollback</code> — setzt auf einen vorherigen Snapshot zurück.</li><li><code>dot drift</code> — erkennt unerwartete Änderungen an verwalteten Dateien.</li><li><code>dot history</code> — zeigt das Apply/Sync-Verlaufsprotokoll.</li><li><code>dot benchmark</code> — misst die Shell-Startzeit.</li><li><code>dot perf</code> — profiliert langsame Shell-Initialisierung.</li></ul><h3 id="erscheinungsbild" tabindex="-1">Erscheinungsbild <a class="header-anchor" href="#erscheinungsbild" aria-label="Permalink to &quot;Erscheinungsbild&quot;">​</a></h3><ul><li><code>dot theme</code> — wechselt das Terminal-Farbschema.</li><li><code>dot wallpaper</code> — setzt das Desktop-Hintergrundbild (macOS).</li><li><code>dot fonts</code> — installiert oder aktualisiert Nerd Fonts.</li><li><code>dot tune</code> — passt UI-Dichte und Prompt-Stil an.</li></ul><h3 id="sicherheit" tabindex="-1">Sicherheit <a class="header-anchor" href="#sicherheit" aria-label="Permalink to &quot;Sicherheit&quot;">​</a></h3><ul><li><code>dot backup</code> — erstellt verschlüsselte Konfigurationssicherungen.</li><li><code>dot encrypt-check</code> — überprüft die Verschlüsselung von Secrets im Ruhezustand.</li><li><code>dot firewall</code> — konfiguriert Host-Firewall-Regeln.</li><li><code>dot telemetry</code> — steuert anonyme Nutzungstelemetrie.</li><li><code>dot dns-doh</code> — aktiviert DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — sperrt den Bildschirm sofort.</li><li><code>dot usb-safety</code> — beschränkt USB-Massenspeicher-Auto-Mount.</li></ul><h3 id="secrets" tabindex="-1">Secrets <a class="header-anchor" href="#secrets" aria-label="Permalink to &quot;Secrets&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — initialisiert das Secrets-Backend (age / GPG).</li><li><code>dot secrets</code> — listet verschlüsselte Secret-Einträge auf.</li><li><code>dot secrets-create</code> — erstellt ein neues verschlüsseltes Secret.</li><li><code>dot ssh-key</code> — generiert oder rotiert SSH-Schlüsselpaare.</li><li><code>dot ssh-cert</code> — fordert ein SSH-Zertifikat von einer CA an.</li></ul><h3 id="ki" tabindex="-1">KI <a class="header-anchor" href="#ki" aria-label="Permalink to &quot;KI&quot;">​</a></h3><ul><li><code>dot ai</code> — öffnet eine interaktive KI-Assistentensitzung.</li><li><code>dot ai-setup</code> — konfiguriert API-Schlüssel für KI-Anbieter.</li><li><code>dot ai-query</code> — sendet eine einmalige Anfrage an ein KI-Modell.</li><li>KI-Tool-Wrapper: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="werkzeuge" tabindex="-1">Werkzeuge <a class="header-anchor" href="#werkzeuge" aria-label="Permalink to &quot;Werkzeuge&quot;">​</a></h3><ul><li><code>dot tools</code> — listet gebündelte CLI-Ersatztools und ihren Status.</li><li><code>dot new</code> — erstellt eine neue Alias- oder Funktionsdatei.</li><li><code>dot sandbox</code> — öffnet eine Wegwerf-Sandbox-Shell.</li><li><code>dot keys</code> — zeigt aktuelle Tastenbelegungen.</li><li><code>dot learn</code> — startet das interaktive Tutorial.</li></ul><h3 id="meta" tabindex="-1">Meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;Meta&quot;">​</a></h3><ul><li><code>dot upgrade</code> — aktualisiert Dotfiles auf die neueste Version.</li><li><code>dot packages</code> — listet installierte, von Dotfiles verwaltete Pakete.</li><li><code>dot version</code> / <code>dot help</code> — gibt Versions- oder Nutzungsinformationen aus.</li></ul><h2 id="beitragen" tabindex="-1">Beitragen <a class="header-anchor" href="#beitragen" aria-label="Permalink to &quot;Beitragen&quot;">​</a></h2><p>Treten Sie der Community bei. Lesen Sie unseren <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CODE-OF-CONDUCT.md" target="_blank" rel="noreferrer">Verhaltenskodex</a> und unsere <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CONTRIBUTING.md" target="_blank" rel="noreferrer">Beitragsrichtlinien</a>.</p>`,41)])])}const g=i(l,[["render",s]]);export{p as __pageData,g as default};
